import React, { useState, useEffect, useRef, useCallback } from 'react';
import axios from 'axios';
import {
  MessageCircle, Send, User, Search, Phone, PhoneOff,
  Settings, Save, X, Circle, Clock, Mic, MicOff, Shield
} from 'lucide-react';

const WS_BASE = window.location.protocol === 'https:' ? 'wss://' : 'ws://';
const WS_HOST = window.location.host; // proxy handled by CRA in dev

const ChatAtendimento = () => {
  const [sessoes, setSessoes] = useState([]);
  const [sessaoSelecionada, setSessaoSelecionada] = useState(null);
  const [mensagens, setMensagens] = useState([]);
  const [novaMensagem, setNovaMensagem] = useState('');
  const [busca, setBusca] = useState('');
  const [filtro, setFiltro] = useState('todas');
  const [loading, setLoading] = useState(false);
  const [showConfig, setShowConfig] = useState(false);
  const [config, setConfig] = useState({
    p2p_enabled: false,
    horario_inicio: '09:00',
    horario_fim: '18:00',
    dias_atendimento: [1, 2, 3, 4, 5],
    mensagem_fora_horario: '',
    mensagem_boas_vindas: '',
  });

  // P2P / gravação
  const [inCall, setInCall] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef(null);
  const recordedChunksRef = useRef([]);
  const peerRef = useRef(null);
  const localStreamRef = useRef(null);
  const remoteAudioRef = useRef(null);

  const wsRef = useRef(null);
  const messagesEndRef = useRef(null);
  const pollRef = useRef(null);

  // ── Carregar sessões ──
  const loadSessoes = useCallback(async () => {
    try {
      const res = await axios.get('/api/admin/chat/sessoes');
      setSessoes(res.data || []);
    } catch (e) {
      console.error('Erro ao carregar sessões:', e);
    }
  }, []);

  // ── Carregar mensagens ──
  const loadMensagens = useCallback(async (sessaoId) => {
    try {
      const res = await axios.get(`/api/admin/chat/sessao/${sessaoId}/mensagens`);
      setMensagens(res.data || []);
    } catch (e) {
      console.error('Erro ao carregar mensagens:', e);
    }
  }, []);

  // ── Carregar config ──
  const loadConfig = useCallback(async () => {
    try {
      const res = await axios.get('/api/admin/chat/config');
      setConfig(res.data || {});
    } catch (e) { /* ignore */ }
  }, []);

  // ── WebSocket ──
  useEffect(() => {
    const token = localStorage.getItem('admin_token');
    if (!token) return;

    const url = `${WS_BASE}${WS_HOST}/ws/chat/admin?token=${token}`;
    const ws = new WebSocket(url);
    wsRef.current = ws;

    ws.onopen = () => console.log('WS admin conectado');
    ws.onmessage = (evt) => {
      try {
        const data = JSON.parse(evt.data);
        if (data.type === 'nova_mensagem') {
          setMensagens((prev) => {
            if (prev.length > 0 && prev[0]?.sessao_id === data.sessao_id) {
              // Somente add se estamos vendo esta sessão - senão ignorar (refresh via poll)
            }
            return [...prev, data];
          });
          // Atualizar lista de sessões
          loadSessoes();
        }
        if (data.type === 'webrtc_offer' || data.type === 'webrtc_answer' || data.type === 'webrtc_ice') {
          handleWebRTCSignal(data);
        }
      } catch (e) { /* ignore */ }
    };
    ws.onclose = () => console.log('WS admin desconectado');

    return () => { ws.close(); };
  }, [loadSessoes]);

  // ── Poll sessões a cada 5s ──
  useEffect(() => {
    loadSessoes();
    loadConfig();
    pollRef.current = setInterval(loadSessoes, 5000);
    return () => clearInterval(pollRef.current);
  }, [loadSessoes, loadConfig]);

  // ── Auto-scroll ──
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [mensagens]);

  // ── Selecionar sessão ──
  const handleSelectSessao = async (s) => {
    setSessaoSelecionada(s);
    await loadMensagens(s.sessao_id);
  };

  // ── Enviar mensagem ──
  const handleEnviar = async (e) => {
    e.preventDefault();
    if (!novaMensagem.trim() || !sessaoSelecionada) return;

    // Via WebSocket se conectado, senão REST
    if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify({
        type: 'mensagem',
        sessao_id: sessaoSelecionada.sessao_id,
        mensagem: novaMensagem,
      }));
      setNovaMensagem('');
    } else {
      try {
        await axios.post('/api/admin/chat/mensagem', {
          sessao_id: sessaoSelecionada.sessao_id,
          mensagem: novaMensagem,
        });
        setNovaMensagem('');
        loadMensagens(sessaoSelecionada.sessao_id);
      } catch (err) {
        alert('Erro ao enviar: ' + (err.response?.data?.detail || 'Erro'));
      }
    }
  };

  // ── Encerrar sessão ──
  const handleEncerrar = async () => {
    if (!sessaoSelecionada) return;
    if (!window.confirm('Encerrar esta sessão?')) return;
    try {
      await axios.post(`/api/admin/chat/encerrar/${sessaoSelecionada.sessao_id}`);
      setSessaoSelecionada(null);
      setMensagens([]);
      loadSessoes();
    } catch (err) {
      alert('Erro: ' + (err.response?.data?.detail || 'Erro'));
    }
  };

  // ── Salvar config ──
  const handleSaveConfig = async () => {
    setLoading(true);
    try {
      await axios.post('/api/admin/chat/config', config);
      alert('Configuração salva!');
      setShowConfig(false);
    } catch (err) {
      alert('Erro: ' + (err.response?.data?.detail || 'Erro'));
    } finally {
      setLoading(false);
    }
  };

  // ── WebRTC P2P ──
  const handleWebRTCSignal = (data) => {
    if (data.type === 'webrtc_offer') {
      startP2PAnswer(data);
    } else if (data.type === 'webrtc_answer' && peerRef.current) {
      peerRef.current.setRemoteDescription(new RTCSessionDescription(data.sdp));
    } else if (data.type === 'webrtc_ice' && peerRef.current) {
      peerRef.current.addIceCandidate(new RTCIceCandidate(data.candidate));
    }
  };

  const startP2PCall = async () => {
    if (!sessaoSelecionada) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      localStreamRef.current = stream;
      const pc = new RTCPeerConnection({ iceServers: [{ urls: 'stun:stun.l.google.com:19302' }] });
      peerRef.current = pc;

      stream.getTracks().forEach(t => pc.addTrack(t, stream));

      pc.ontrack = (e) => {
        if (remoteAudioRef.current) remoteAudioRef.current.srcObject = e.streams[0];
      };
      pc.onicecandidate = (e) => {
        if (e.candidate && wsRef.current?.readyState === WebSocket.OPEN) {
          wsRef.current.send(JSON.stringify({
            type: 'webrtc_ice',
            sessao_id: sessaoSelecionada.sessao_id,
            candidate: e.candidate,
          }));
        }
      };

      const offer = await pc.createOffer();
      await pc.setLocalDescription(offer);
      if (wsRef.current?.readyState === WebSocket.OPEN) {
        wsRef.current.send(JSON.stringify({
          type: 'webrtc_offer',
          sessao_id: sessaoSelecionada.sessao_id,
          sdp: offer,
        }));
      }
      setInCall(true);
    } catch (err) {
      alert('Erro ao iniciar chamada: ' + err.message);
    }
  };

  const startP2PAnswer = async (data) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      localStreamRef.current = stream;
      const pc = new RTCPeerConnection({ iceServers: [{ urls: 'stun:stun.l.google.com:19302' }] });
      peerRef.current = pc;

      stream.getTracks().forEach(t => pc.addTrack(t, stream));

      pc.ontrack = (e) => {
        if (remoteAudioRef.current) remoteAudioRef.current.srcObject = e.streams[0];
      };
      pc.onicecandidate = (e) => {
        if (e.candidate && wsRef.current?.readyState === WebSocket.OPEN) {
          wsRef.current.send(JSON.stringify({
            type: 'webrtc_ice',
            sessao_id: data.sessao_id,
            candidate: e.candidate,
          }));
        }
      };

      await pc.setRemoteDescription(new RTCSessionDescription(data.sdp));
      const answer = await pc.createAnswer();
      await pc.setLocalDescription(answer);
      if (wsRef.current?.readyState === WebSocket.OPEN) {
        wsRef.current.send(JSON.stringify({
          type: 'webrtc_answer',
          sessao_id: data.sessao_id,
          sdp: answer,
        }));
      }
      setInCall(true);
      setSessaoSelecionada((prev) => prev || sessoes.find(s => s.sessao_id === data.sessao_id));
    } catch (err) {
      console.error('Erro ao atender chamada:', err);
    }
  };

  const endCall = () => {
    peerRef.current?.close();
    peerRef.current = null;
    localStreamRef.current?.getTracks().forEach(t => t.stop());
    localStreamRef.current = null;
    setInCall(false);
    stopRecording();
  };

  // ── Gravação ──
  const startRecording = () => {
    if (!localStreamRef.current) return;
    recordedChunksRef.current = [];
    try {
      const mr = new MediaRecorder(localStreamRef.current, { mimeType: 'audio/webm' });
      mr.ondataavailable = (e) => { if (e.data.size > 0) recordedChunksRef.current.push(e.data); };
      mr.start();
      mediaRecorderRef.current = mr;
      setIsRecording(true);
    } catch (err) {
      alert('Erro ao iniciar gravação: ' + err.message);
    }
  };

  const stopRecording = async () => {
    if (!mediaRecorderRef.current || mediaRecorderRef.current.state === 'inactive') {
      setIsRecording(false);
      return;
    }
    mediaRecorderRef.current.stop();
    setIsRecording(false);

    // Esperar dados finais
    await new Promise(r => setTimeout(r, 500));

    if (recordedChunksRef.current.length === 0 || !sessaoSelecionada) return;

    const blob = new Blob(recordedChunksRef.current, { type: 'audio/webm' });
    const formData = new FormData();
    formData.append('file', blob, 'gravacao.webm');

    try {
      const res = await axios.post(`/api/admin/chat/gravar/${sessaoSelecionada.sessao_id}`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      alert(`Gravação salva! Protocolo: ${res.data.protocolo}`);
      loadMensagens(sessaoSelecionada.sessao_id);
    } catch (err) {
      alert('Erro ao salvar gravação: ' + (err.response?.data?.detail || 'Erro'));
    }
  };

  // ── Filtro sessões ──
  const sessoesFiltradas = sessoes.filter((s) => {
    const matchBusca = !busca ||
      (s.cliente_nome || '').toLowerCase().includes(busca.toLowerCase()) ||
      (s.cliente_email || '').toLowerCase().includes(busca.toLowerCase()) ||
      (s.protocolo || '').toLowerCase().includes(busca.toLowerCase());
    const matchFiltro = filtro === 'todas' ||
      (filtro === 'ativas' && s.status === 'ativa') ||
      (filtro === 'encerradas' && s.status === 'encerrada');
    return matchBusca && matchFiltro;
  });

  const diasSemana = [
    { value: 1, label: 'Seg' }, { value: 2, label: 'Ter' }, { value: 3, label: 'Qua' },
    { value: 4, label: 'Qui' }, { value: 5, label: 'Sex' }, { value: 6, label: 'Sáb' }, { value: 7, label: 'Dom' },
  ];

  return (
    <div className="h-[calc(100vh-8rem)]">
      {/* Config Modal */}
      {showConfig && (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-xl max-w-lg w-full p-6 max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-bold text-gray-900">Configurações do Chat</h3>
              <button onClick={() => setShowConfig(false)}><X className="h-5 w-5 text-gray-400" /></button>
            </div>

            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <label className="text-sm font-medium text-gray-700">Ligação P2P habilitada</label>
                <button
                  onClick={() => setConfig({ ...config, p2p_enabled: !config.p2p_enabled })}
                  className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${config.p2p_enabled ? 'bg-green-500' : 'bg-gray-300'}`}
                >
                  <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${config.p2p_enabled ? 'translate-x-6' : 'translate-x-1'}`} />
                </button>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Horário início</label>
                  <input type="time" value={config.horario_inicio} onChange={(e) => setConfig({ ...config, horario_inicio: e.target.value })} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Horário fim</label>
                  <input type="time" value={config.horario_fim} onChange={(e) => setConfig({ ...config, horario_fim: e.target.value })} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm" />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Dias de atendimento</label>
                <div className="flex gap-2 flex-wrap">
                  {diasSemana.map((d) => (
                    <button
                      key={d.value}
                      onClick={() => {
                        const dias = config.dias_atendimento || [];
                        setConfig({
                          ...config,
                          dias_atendimento: dias.includes(d.value) ? dias.filter(x => x !== d.value) : [...dias, d.value],
                        });
                      }}
                      className={`px-3 py-1 rounded-full text-xs font-medium ${(config.dias_atendimento || []).includes(d.value) ? 'bg-blue-500 text-white' : 'bg-gray-100 text-gray-600'}`}
                    >
                      {d.label}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Mensagem fora do horário</label>
                <textarea value={config.mensagem_fora_horario} onChange={(e) => setConfig({ ...config, mensagem_fora_horario: e.target.value })} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm" rows={2} />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Mensagem de boas-vindas</label>
                <textarea value={config.mensagem_boas_vindas} onChange={(e) => setConfig({ ...config, mensagem_boas_vindas: e.target.value })} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm" rows={2} />
              </div>

              <button onClick={handleSaveConfig} disabled={loading} className="w-full bg-blue-600 text-white font-medium py-2 rounded-lg hover:bg-blue-700 disabled:opacity-50 flex items-center justify-center gap-2">
                <Save className="h-4 w-4" /> Salvar Configuração
              </button>
            </div>
          </div>
        </div>
      )}

      <audio ref={remoteAudioRef} autoPlay />

      <div className="bg-white rounded-lg shadow h-full flex">
        {/* Lista lateral */}
        <div className="w-80 border-r border-gray-200 flex flex-col">
          <div className="p-3 border-b border-gray-200">
            <div className="flex items-center justify-between mb-3">
              <h2 className="text-lg font-bold text-gray-900 flex items-center gap-2">
                <MessageCircle className="h-5 w-5 text-blue-600" /> Chat
              </h2>
              <button onClick={() => { loadConfig(); setShowConfig(true); }} className="p-1 rounded hover:bg-gray-100">
                <Settings className="h-5 w-5 text-gray-500" />
              </button>
            </div>
            <div className="relative mb-2">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
              <input type="text" placeholder="Buscar..." value={busca} onChange={(e) => setBusca(e.target.value)} className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg text-sm" />
            </div>
            <select value={filtro} onChange={(e) => setFiltro(e.target.value)} className="w-full px-3 py-1.5 border border-gray-300 rounded-lg text-sm">
              <option value="todas">Todas</option>
              <option value="ativas">Ativas</option>
              <option value="encerradas">Encerradas</option>
            </select>
          </div>

          <div className="flex-1 overflow-y-auto">
            {sessoesFiltradas.length === 0 ? (
              <div className="p-4 text-center text-gray-400">
                <MessageCircle className="h-8 w-8 mx-auto mb-2" />
                <p className="text-sm">Nenhuma conversa</p>
              </div>
            ) : sessoesFiltradas.map((s) => (
              <div
                key={s.sessao_id}
                onClick={() => handleSelectSessao(s)}
                className={`p-3 cursor-pointer border-b border-gray-100 transition-colors ${sessaoSelecionada?.sessao_id === s.sessao_id ? 'bg-blue-50 border-l-4 border-l-blue-500' : 'hover:bg-gray-50'}`}
              >
                <div className="flex items-start justify-between">
                  <div className="flex items-center gap-2 min-w-0">
                    <div className="relative">
                      <div className="bg-gray-200 rounded-full p-1.5">
                        <User className="h-4 w-4 text-gray-600" />
                      </div>
                      {s.online && <Circle className="absolute -bottom-0.5 -right-0.5 h-3 w-3 text-green-500 fill-green-500" />}
                    </div>
                    <div className="min-w-0">
                      <p className="text-sm font-medium text-gray-900 truncate">{s.cliente_nome || 'Cliente'}</p>
                      <p className="text-xs text-gray-500 truncate">{s.protocolo || s.cliente_email}</p>
                      <p className="text-xs text-gray-400 truncate">{s.ultima_mensagem}</p>
                    </div>
                  </div>
                  <div className="flex flex-col items-end gap-1 flex-shrink-0">
                    <span className={`text-[10px] px-1.5 py-0.5 rounded-full font-medium ${s.status === 'ativa' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500'}`}>
                      {s.status === 'ativa' ? 'Ativo' : 'Encerrado'}
                    </span>
                    {s.nao_lidas > 0 && (
                      <span className="bg-blue-600 text-white text-[10px] font-bold rounded-full h-5 w-5 flex items-center justify-center">{s.nao_lidas}</span>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Chat area */}
        <div className="flex-1 flex flex-col">
          {sessaoSelecionada ? (
            <>
              {/* Header */}
              <div className="p-3 border-b border-gray-200 bg-gray-50 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="bg-blue-600 rounded-full p-2"><User className="h-4 w-4 text-white" /></div>
                  <div>
                    <p className="text-sm font-semibold text-gray-900">{sessaoSelecionada.cliente_nome || 'Cliente'}</p>
                    <p className="text-xs text-gray-500">{sessaoSelecionada.protocolo} &middot; {sessaoSelecionada.cliente_email}</p>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  {config.p2p_enabled && !inCall && sessaoSelecionada.status === 'ativa' && (
                    <button onClick={startP2PCall} className="p-2 rounded-lg bg-green-500 text-white hover:bg-green-600" title="Iniciar chamada">
                      <Phone className="h-4 w-4" />
                    </button>
                  )}
                  {inCall && (
                    <>
                      <button onClick={endCall} className="p-2 rounded-lg bg-red-500 text-white hover:bg-red-600" title="Encerrar chamada">
                        <PhoneOff className="h-4 w-4" />
                      </button>
                      {!isRecording ? (
                        <button onClick={startRecording} className="p-2 rounded-lg bg-yellow-500 text-white hover:bg-yellow-600" title="Gravar">
                          <Mic className="h-4 w-4" />
                        </button>
                      ) : (
                        <button onClick={stopRecording} className="p-2 rounded-lg bg-red-600 text-white hover:bg-red-700 animate-pulse" title="Parar gravação">
                          <MicOff className="h-4 w-4" />
                        </button>
                      )}
                    </>
                  )}
                  {sessaoSelecionada.status === 'ativa' && (
                    <button onClick={handleEncerrar} className="p-2 rounded-lg bg-gray-200 text-gray-600 hover:bg-gray-300" title="Encerrar sessão">
                      <X className="h-4 w-4" />
                    </button>
                  )}
                </div>
              </div>

              {/* Mensagens */}
              <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-gray-50">
                {mensagens.map((m, idx) => (
                  <div key={m.id || idx} className={`flex ${m.remetente === 'atendente' ? 'justify-end' : m.remetente === 'sistema' ? 'justify-center' : 'justify-start'}`}>
                    {m.remetente === 'sistema' ? (
                      <div className="bg-yellow-100 text-yellow-800 text-xs px-3 py-1.5 rounded-full max-w-sm text-center">
                        <Shield className="h-3 w-3 inline mr-1" />{m.mensagem}
                      </div>
                    ) : (
                      <div className={`max-w-xs lg:max-w-md px-4 py-2 rounded-2xl ${m.remetente === 'atendente' ? 'bg-blue-600 text-white rounded-br-md' : 'bg-white text-gray-900 shadow rounded-bl-md'}`}>
                        <p className="text-sm whitespace-pre-wrap">{m.mensagem}</p>
                        <p className={`text-[10px] mt-1 ${m.remetente === 'atendente' ? 'text-blue-200' : 'text-gray-400'}`}>
                          {m.data_criacao ? new Date(m.data_criacao).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }) : ''}
                        </p>
                      </div>
                    )}
                  </div>
                ))}
                <div ref={messagesEndRef} />
              </div>

              {/* Input */}
              {sessaoSelecionada.status === 'ativa' && (
                <form onSubmit={handleEnviar} className="p-3 border-t border-gray-200 bg-white">
                  <div className="flex gap-2">
                    <input
                      type="text"
                      value={novaMensagem}
                      onChange={(e) => setNovaMensagem(e.target.value)}
                      placeholder="Digite sua mensagem..."
                      className="flex-1 px-4 py-2 border border-gray-300 rounded-full focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
                    />
                    <button type="submit" disabled={!novaMensagem.trim()} className="bg-blue-600 text-white p-2.5 rounded-full hover:bg-blue-700 disabled:opacity-50">
                      <Send className="h-4 w-4" />
                    </button>
                  </div>
                </form>
              )}
            </>
          ) : (
            <div className="flex-1 flex items-center justify-center">
              <div className="text-center">
                <MessageCircle className="h-16 w-16 text-gray-200 mx-auto mb-4" />
                <p className="text-gray-400 text-lg">Selecione uma conversa</p>
                <p className="text-gray-300 text-sm mt-1">As mensagens aparecerão aqui</p>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ChatAtendimento;
